    result = _tool_answer_result(tool_result)
    if not isinstance(result, dict):
        return {}
    image_refs = result.get("image_refs")
    image_links = result.get("image_links")
    metadata: dict[str, Any] = {}
    if isinstance(image_refs, list):
        metadata["image_refs"] = [item for item in image_refs if isinstance(item, dict)]
