def build_image_refs(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    refs: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for item in items:
        if not isinstance(item, dict):
            continue
        for ref in item.get("image_refs", []):
            if not isinstance(ref, dict):
                continue
            url = clean_text(ref.get("url"))
            if not url:
                continue
            normalized = {
                "url": url,
                "document_id": clean_text(ref.get("document_id")) or "",
                "document_name": clean_text(ref.get("document_name")) or "",
                "dataset_id": clean_text(ref.get("dataset_id")) or "",
            }
            key = (
                normalized["url"],
                normalized["document_id"],
                normalized["document_name"],
                normalized["dataset_id"],
            )
            if key in seen:
                continue
            seen.add(key)
            refs.append(normalized)
    return refs


